package config

import (
	"bufio"
	"fmt"
	"os"
	"strings"
)

// LoadEnv loads environment variables following this precedence (lowest → highest):
//  1. Values from ../.env
//  2. Values from ../.env.<LINKSHORTENER_ENV>  (if LINKSHORTENER_ENV is set at the OS level)
//  3. Non-empty OS-level environment variables  (always win)
//
// LINKSHORTENER_ENV itself is always taken from the OS; .env files cannot override it.
func LoadEnv() error {
	fileVars, err := parseEnvFile("../.env")
	if err != nil {
		return fmt.Errorf("loading .env: %w", err)
	}

	// LINKSHORTENER_ENV is always the OS value — read it before any file override.
	envName := os.Getenv("LINKSHORTENER_ENV")

	if envName != "" {
		specific, err := parseEnvFile("../.env." + envName)
		if err != nil {
			return fmt.Errorf("loading .env.%s: %w", envName, err)
		}
		// .env.<envName> overrides .env
		for k, v := range specific {
			fileVars[k] = v
		}
	}

	// Apply collected file values, but OS non-empty values always win.
	for key, fileVal := range fileVars {
		if key == "LINKSHORTENER_ENV" {
			// Never let files override this variable.
			continue
		}
		if osVal := os.Getenv(key); osVal != "" {
			// OS value is non-empty — it takes precedence, keep it.
			continue
		}
		if err := os.Setenv(key, fileVal); err != nil {
			return fmt.Errorf("setting env var %s: %w", key, err)
		}
	}

	return nil
}

// parseEnvFile reads a .env-style file and returns its key/value pairs.
// Missing files are silently ignored (returns empty map, nil error).
// Each non-blank, non-comment line must follow the format: KEY=VALUE
// Values may optionally be surrounded by single or double quotes.
func parseEnvFile(path string) (map[string]string, error) {
	f, err := os.Open(path) //nolint:gosec // path is constructed from safe constants + envName
	if os.IsNotExist(err) {
		return map[string]string{}, nil
	}
	if err != nil {
		return nil, err
	}
	defer f.Close() //nolint:errcheck // read-only file, close error is not actionable

	vars := make(map[string]string)
	scanner := bufio.NewScanner(f)
	lineNo := 0

	for scanner.Scan() {
		lineNo++
		line := strings.TrimSpace(scanner.Text())

		if line == "" || strings.HasPrefix(line, "#") {
			continue
		}

		eq := strings.IndexByte(line, '=')
		if eq < 0 {
			return nil, fmt.Errorf("%s line %d: missing '='", path, lineNo)
		}

		key := strings.TrimSpace(line[:eq])
		val := strings.TrimSpace(line[eq+1:])

		if len(val) >= 2 {
			if (val[0] == '"' && val[len(val)-1] == '"') ||
				(val[0] == '\'' && val[len(val)-1] == '\'') {
				val = val[1 : len(val)-1]
			}
		}

		if key != "" {
			vars[key] = val
		}
	}

	if err := scanner.Err(); err != nil {
		return nil, fmt.Errorf("reading %s: %w", path, err)
	}

	return vars, nil
}

